INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '3eb43be9-7eec-498e-b561-146c2d4128dc',
  '00000000-0000-0000-0000-000000000001',
  $escape$Matplotlib — Master the Figure/Axes API for Publication-Quality Charts$escape$,
  $escape$The pyplot state machine (plt.plot()) works for quick plots but fights you at scale. Switch to the object-oriented Figure/Axes API: fig, ax = plt.subplots(). Every element — ticks, spines, legends — lives on the Axes object, giving you explicit control.

For multi-panel figures, plt.subplots(2, 2, figsize=(8, 6)) returns a 2D array of Axes. Use constrained_layout=True instead of tight_layout() — it handles colorbars and shared labels without overlap.

Publication tricks: set ax.spines[['top','right']].set_visible(False) to remove chart junk. Use ax.tick_params(direction='in', length=4) for journal-style inward ticks. Set plt.rcParams['font.family'] = 'serif' globally or pass fontdict per call.

For consistent styling across figures, define a custom rcParams dict or use plt.style.use() with a .mplstyle file. Export with fig.savefig('plot.pdf', dpi=300, bbox_inches='tight') — PDF preserves vector quality, and bbox_inches='tight' clips whitespace.$escape$,
  $escape$import matplotlib.pyplot as plt
import numpy as np

x = np.linspace(0, 2 * np.pi, 200)
fig, (ax1, ax2) = plt.subplots(1, 2, figsize=(10, 4), constrained_layout=True)

ax1.plot(x, np.sin(x), color='#2563eb', linewidth=1.5)
ax1.set_title('Sine', fontsize=12, fontweight='bold')
ax1.spines[['top', 'right']].set_visible(False)
ax1.tick_params(direction='in', length=4)

ax2.plot(x, np.cos(x), color='#dc2626', linewidth=1.5)
ax2.set_title('Cosine', fontsize=12, fontweight='bold')
ax2.spines[['top', 'right']].set_visible(False)
ax2.tick_params(direction='in', length=4)

fig.savefig('trig.pdf', dpi=300, bbox_inches='tight')$escape$,
  $escape$python$escape$,
