INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '9e077c0a-b33c-483b-b02f-3c12b02c116f',
  '00000000-0000-0000-0000-000000000001',
  $escape$Matplotlib + Seaborn — Supercharge Statistical Plots Without Leaving pyplot$escape$,
  $escape$Seaborn builds directly on top of matplotlib's Figure and Axes objects, meaning every seaborn plot is a matplotlib plot you can customize further. Call sns.set_theme() to globally override matplotlib's rcParams — fonts, grid styles, and color palettes all flow through matplotlib's rendering engine. The real power is the return value: functions like sns.histplot() and sns.boxplot() return matplotlib Axes objects, so you can chain .set_xlabel(), .set_title(), or overlay additional plt.axhline() calls seamlessly. For Pandas DataFrames, seaborn accepts column names as strings via the data= parameter, eliminating manual array extraction. Use sns.FacetGrid to generate subplot grids that map to matplotlib's plt.subplots() under the hood — call .fig.suptitle() to add a figure-level title. When you need fine control, access the underlying Figure with plt.gcf() after any seaborn call. This interop means you never hit a wall: seaborn handles the statistics, matplotlib handles the pixel-perfect tweaks.$escape$,
  $escape$import seaborn as sns
import matplotlib.pyplot as plt
import pandas as pd

df = pd.DataFrame({"category": ["A"]*50 + ["B"]*50,
                   "value": list(range(50)) + list(range(10, 60))})

sns.set_theme(style="whitegrid", palette="muted")
ax = sns.boxplot(data=df, x="category", y="value")
ax.set_title("Distribution by Category", fontsize=14)
ax.axhline(y=30, color="red", linestyle="--", label="threshold")
ax.legend()
plt.tight_layout()
plt.show()$escape$,
  $escape$python$escape$,
